const fs = require('fs');
const path = require('path');

const projectPath = $input.first().json.path;

if (!projectPath) {
  throw new Error('Caminho é obrigatório');
}

if (!fs.existsSync(projectPath)) {
  throw new Error('Diretório não encontrado: ' + projectPath);
}

const stat = fs.statSync(projectPath);
if (!stat.isDirectory()) {
  throw new Error('O caminho deve ser um diretório');
}

const projectName = $input.first().json.projectName || path.basename(projectPath);

// Detecta tipo
const detectType = (dir) => {
  if (fs.existsSync(path.join(dir, 'wp-config.php'))) return 'wordpress';
  if (fs.existsSync(path.join(dir, 'next.config.js'))) return 'nextjs';
  if (fs.existsSync(path.join(dir, 'package.json'))) return 'nodejs';
  if (fs.existsSync(path.join(dir, 'composer.json'))) return 'php';
  if (fs.existsSync(path.join(dir, 'requirements.txt'))) return 'python';
  if (fs.existsSync(path.join(dir, 'go.mod'))) return 'go';
  if (fs.existsSync(path.join(dir, 'Cargo.toml'))) return 'rust';
  return 'unknown';
};

// Detecta stack
const detectStack = (dir) => {
  const stack = [];
  if (fs.existsSync(path.join(dir, 'package.json'))) {
    try {
      const pkg = JSON.parse(fs.readFileSync(path.join(dir, 'package.json'), 'utf-8'));
      stack.push('Node.js');
      if (pkg.dependencies?.next || pkg.devDependencies?.next) stack.push('Next.js');
      if (pkg.dependencies?.react) stack.push('React');
      if (pkg.dependencies?.express) stack.push('Express');
    } catch {}
  }
  return stack;
};

const type = detectType(projectPath);

return [{
  json: {
    path: projectPath,
    name: projectName,
    type: type,
    techStack: detectStack(projectPath)
  }
}];

const result = $input.first().json;

if (result.success) {
  return [{
    json: {
      message: '✅ Projeto **' + result.projectData.name + '** criado com sucesso!\n\nTipo: ' + result.projectData.type + '\nTecnologias: ' + (result.projectData.techStack?.join(', ') || 'Nenhuma')\n\nProjeto ID: ' + result.projectId
    }
  }];
} else {
  return [{
    json: {
      message: '❌ Erro: ' + result.error
    }
  }];
}
